// ==UserScript==
// @name         Copy to Markdown - neetcode.io
// @namespace    ipwnponies
// @icon        data:image/x-icon;base64,
// @version      1.0.1
// @description  Add hotkey to copy the problem, solutions, and own code and copy to clipboard as markdown
// @match        https://neetcode.io/*
// @require      https://cdn.jsdelivr.net/npm/turndown@7.2.4/dist/turndown.js
// @require      https://cdn.jsdelivr.net/npm/@violentmonkey/shortcut@1
// @grant        none
// ==/UserScript==
/* global TurndownService */

// ---- config -------------------------------------------------------
const DEBUG = true; // set false to silence console output

// class fragments that mean "drop this element entirely"
const SKIP_CLASSES = ['video-container', 'visualizer-container'];

// <details> summary text (lowercased) to drop entirely, regardless of
// which class variant wraps it (NeetCode renders the "Company Tags"
// block differently for Pro vs non-Pro accounts)
const SKIP_DETAILS_SUMMARIES = ['company tags'];

// custom (hyphenated) tags that get their own rule below, so the
// "unhandled custom element" tracker shouldn't flag them
const HANDLED_CUSTOM_TAGS = new Set([
  'app-code-tabs',
  'app-algo-visualizer',
  'app-prereq-cards',
  'app-carbon',
  'app-interview-survey',
]);

// ---- logging --------------------------------------------------------
const PREFIX = '[nc2md]';
function dlog(...args) {
  if (DEBUG) console.log(PREFIX, ...args);
}
function dwarn(...args) {
  if (DEBUG) console.warn(PREFIX, ...args);
}
function derror(...args) {
  console.error(PREFIX, ...args);
}

// tracks custom elements that fell through to "pass children through
// unchanged" - the likely spot where a different problem page breaks
let seenCustomTags = new Map();

// ---- small helpers --------------------------------------------------------
function cleanText(s) {
  return s.replace(/\u00A0/g, ' ').replace(/\s+/g, ' ');
}

function rawText(el) {
  return el.textContent.replace(/\u00A0/g, ' ');
}

// escape chars that would be misread as markdown syntax in plain
// (non-code) text we insert ourselves (e.g. katex annotations)
function escapeMd(s) {
  return s.replace(/([*_`])/g, '\\$1');
}

// Build a fenced code block from a <pre>, using its / its <code>'s
// language-xxx class for the fence language.
function fencedBlock(preEl) {
  const codeEl = preEl.querySelector('code') || preEl;
  const m = (preEl.className || codeEl.className || '').match(/language-(\w+)/);
  const lang = m ? m[1] : '';
  if (!m) dwarn('fencedBlock: no language-* class found on', preEl);
  return `\`\`\`${lang}\n${rawText(codeEl).replace(/\s+$/, '')}\n\`\`\`\n`;
}

// Grab the currently-active tab from an <app-code-tabs> block.
function codeTabsToMarkdown(node) {
  const panels = node.querySelectorAll('.code-tab-panel');
  let active = node.querySelector('.code-tab-panel.active');
  if (!active) {
    dwarn('codeTabsToMarkdown: no .code-tab-panel.active, falling back to first of', panels.length, 'panels');
    [active] = panels;
  }
  if (!active) {
    dwarn('codeTabsToMarkdown: no .code-tab-panel found at all');
    return '';
  }
  const pre = active.querySelector('pre');
  if (!pre) {
    dwarn('codeTabsToMarkdown: active panel has no <pre>', active);
    return '';
  }
  return `\n\n${fencedBlock(pre)}\n`;
}

// ---- Turndown setup -------------------------------------------------------
function buildTurndownService() {
  if (typeof TurndownService === 'undefined') {
    derror(
      'TurndownService is undefined - the @require from jsdelivr did not load (check network tab / Violentmonkey cache)',
    );
    return null;
  }

  const td = new TurndownService({
    headingStyle: 'atx',
    codeBlockStyle: 'fenced',
    bulletListMarker: '-',
  });

  // fully drop noise elements
  td.remove([
    'script',
    'style',
    'svg',
    'button',
    'fa-icon',
    'iframe',
    'noscript',
    'input',
    'label',
    'app-algo-visualizer',
    'app-prereq-cards',
    'app-carbon',
    'app-interview-survey',
  ]);

  // drop elements identified by class rather than tag
  td.addRule('skipByClass', {
    filter: (node) => {
      const cls = (node.getAttribute && node.getAttribute('class')) || '';
      return SKIP_CLASSES.some((c) => cls.includes(c));
    },
    replacement: () => '',
  });

  // KaTeX: use the hidden LaTeX-ish annotation instead of the rendered HTML soup
  td.addRule('katex', {
    filter: (node) => ((node.getAttribute && node.getAttribute('class')) || '').includes('katex'),
    replacement: (content, node) => {
      const ann = node.querySelector('annotation');
      if (!ann) {
        dwarn('katex element with no <annotation>', node);
        return '';
      }
      return escapeMd(cleanText(ann.textContent));
    },
  });

  // <details><summary>Label</summary>...content...</details>
  //   -> **Label:**\n\ncontent
  td.addRule('summary', {
    filter: 'summary',
    replacement: () => '',
  });
  td.addRule('details', {
    filter: 'details',
    replacement: (content, node) => {
      const summary = node.querySelector('summary');
      if (!summary) {
        dwarn('details element with no <summary>', node);
        return content;
      }
      const label = cleanText(summary.textContent);
      if (SKIP_DETAILS_SUMMARIES.includes(label.toLowerCase())) {
        dlog(`skipping <details> block titled "${label}"`);
        return '';
      }
      return `\n\n**${label}:**\n\n${content.trim()}\n\n`;
    },
  });

  // Links: use the resolved absolute URL (node.href) instead of the raw
  // (possibly relative) href attribute
  td.addRule('absoluteLink', {
    filter: (node) => node.nodeName === 'A' && node.getAttribute('href'),
    replacement: (content, node) => `[${content}](${node.href})`,
  });

  // <app-code-tabs> -> fenced block for whichever language tab is active
  td.addRule('codeTabs', {
    filter: (node) => node.nodeName === 'APP-CODE-TABS',
    replacement: (content, node) => codeTabsToMarkdown(node),
  });

  // Anything else with a hyphenated tag name (custom elements) that we
  // haven't special-cased: pass its converted content through, but log
  // it so we notice if some other problem page leans on a component we
  // don't know about.
  td.addRule('trackCustomElements', {
    filter: (node) => node.nodeName.includes('-') && !HANDLED_CUSTOM_TAGS.has(node.nodeName.toLowerCase()),
    replacement: (content, node) => {
      const tag = node.nodeName.toLowerCase();
      seenCustomTags.set(tag, (seenCustomTags.get(tag) || 0) + 1);
      return content;
    },
  });

  return td;
}

function articleToMarkdown(td, article) {
  const main = article.querySelector('.my-article-component-container');
  if (!main) {
    dwarn('articleToMarkdown: no .my-article-component-container inside', article);
    return '';
  }
  return td.turndown(main).trim();
}

// Sort Monaco's virtualized .view-line divs by their "top" offset and
// join into plain code text. Trims trailing whitespace from each line
// and any trailing blank lines overall.
function extractUserCode() {
  const editors = document.querySelectorAll('.view-lines.monaco-mouse-cursor-text');
  dlog('monaco .view-lines candidates found:', editors.length);
  editors.forEach((ed, i) => {
    dlog(`  candidate #${i}: ${ed.querySelectorAll('.view-line').length} .view-line element(s)`);
  });
  for (const ed of editors) {
    const lines = Array.from(ed.querySelectorAll('.view-line'));
    if (lines.length) {
      lines.sort((a, b) => (parseFloat(a.style.top) || 0) - (parseFloat(b.style.top) || 0));
      return lines
        .map((l) => rawText(l).replace(/[ \t]+$/, ''))
        .join('\n')
        .replace(/\s+$/, '');
    }
  }
  return '';
}

// ---- main build -------------------------------------------------------
function buildMarkdown() {
  console.group(`${PREFIX} build`);
  seenCustomTags = new Map();
  const parts = [];

  const td = buildTurndownService();
  if (!td) {
    console.groupEnd();
    return null; // signals "Turndown unavailable" to the caller
  }

  // --- title / difficulty ---
  try {
    const titleEl = document.querySelector('.problem-title');
    const diffEl = document.querySelector('.difficulty-pill');
    dlog('title:', titleEl ? titleEl.textContent.trim() : 'NOT FOUND (.problem-title)');
    dlog('difficulty:', diffEl ? diffEl.textContent.trim() : 'NOT FOUND (.difficulty-pill)');
    if (titleEl) {
      let title = `# ${titleEl.textContent.trim()}`;
      if (diffEl) title += ` (${diffEl.textContent.trim()})`;
      parts.push(`${title}\n`);
    }
  } catch (e) {
    derror('title section failed', e);
  }

  // --- problem description ---
  try {
    const questionArticle = document.querySelector('.question-tab app-article');
    dlog('question app-article found:', !!questionArticle);
    if (questionArticle) {
      const md = articleToMarkdown(td, questionArticle);
      dlog('question markdown length:', md.length);
      if (!md) dwarn('question article found but produced empty markdown');
      if (md) parts.push(`## Problem\n\n${md}`);
    } else {
      dwarn('No ".question-tab app-article" - selector may not match on this page/layout');
    }
  } catch (e) {
    derror('question section failed', e);
  }

  // --- your code ---
  try {
    const userCode = extractUserCode();
    dlog('extracted user code length:', userCode.length);
    if (!userCode) {
      dwarn(
        'No code extracted - check .view-lines.monaco-mouse-cursor-text / .view-line selectors, or editor may not be rendered yet',
      );
    }
    if (userCode) parts.push(`## My Code\n\n\`\`\`\n${userCode}\n\`\`\``);
  } catch (e) {
    derror('user code section failed', e);
  }

  // --- NeetCode solution ---
  try {
    const solutionsTab = document.querySelector('.solutions-tab');
    dlog('solutions tab found:', !!solutionsTab);
    if (solutionsTab) {
      const articles = solutionsTab.querySelectorAll('app-article');
      dlog('  app-article count in solutions tab:', articles.length);
      const chunks = [];
      articles.forEach((a, i) => {
        if (a.querySelector('.video-container')) {
          dlog(`  article #${i}: skipped (contains .video-container)`);
          return;
        }
        const md = articleToMarkdown(td, a);
        dlog(`  article #${i}: markdown length ${md.length}`);
        if (md) chunks.push(md);
      });
      if (chunks.length) {
        parts.push(`## NeetCode Solution\n\n${chunks.join('\n\n---\n\n')}`);
      } else {
        dwarn('Solutions tab present but produced no usable content');
      }
    } else {
      dlog('No .solutions-tab in DOM - open the Solutions tab before copying if you want it included');
    }
  } catch (e) {
    derror('solutions section failed', e);
  }

  if (seenCustomTags.size) {
    dwarn(
      'Custom elements passed through without special handling (check these if output looks wrong):',
      Object.fromEntries(seenCustomTags),
    );
  } else {
    dlog('No unhandled custom elements encountered.');
  }

  parts.push(`\n_Source: ${window.location.href}_`);

  const result = parts.join('\n\n').trim();
  dlog('total parts:', parts.length, '| total length:', result.length);
  if (parts.length <= 1) dwarn('Almost nothing was extracted - check the warnings above');
  console.groupEnd();
  return result;
}

// ---- UI feedback -------------------------------------------------------
function showToast(msg) {
  let t = document.getElementById('nc2md-toast');
  if (!t) {
    t = document.createElement('div');
    t.id = 'nc2md-toast';
    t.style.cssText = [
      'position:fixed',
      'top:16px',
      'right:16px',
      'z-index:999999',
      'background:#222',
      'color:#fff',
      'padding:8px 14px',
      'border-radius:6px',
      'font:14px sans-serif',
      'opacity:0',
      'transition:opacity .2s',
    ].join(';');
    document.body.appendChild(t);
  }
  t.textContent = msg;
  t.style.opacity = '1';
  clearTimeout(t.hideTimer);
  t.hideTimer = setTimeout(() => {
    t.style.opacity = '0';
  }, 1800);
}

async function copyText(text) {
  try {
    await navigator.clipboard.writeText(text);
    return true;
  } catch (e) {
    dwarn('navigator.clipboard.writeText failed, falling back to execCommand', e);
    const ta = document.createElement('textarea');
    ta.value = text;
    ta.style.position = 'fixed';
    ta.style.opacity = '0';
    document.body.appendChild(ta);
    ta.select();
    const ok = document.execCommand('copy');
    ta.remove();
    return ok;
  }
}

// ---- hotkey -------------------------------------------------------
VM.shortcut.register('alt-shift-c', async () => {
  const md = buildMarkdown();
  if (md === null) {
    showToast('Turndown failed to load (see console)');
    return;
  }
  const ok = await copyText(md);
  const status = ok ? `Copied (${md.length} chars)` : 'Copy failed (see console)';
  showToast(status);
  dlog('clipboard write ok:', ok);
});
